<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class Router extends Model { protected $guarded = []; public function olt() { return $this->belongsTo(Olt::class, 'mapped_olt_id'); } public function pools() { return $this->hasMany(IpPool::class); } public function addresses() { return $this->hasMany(RouterAddress::class); } public function routes() { return $this->hasMany(RouterRoute::class); } public function wireguardInterfaces() { return $this->hasMany(WireguardInterface::class); } public function wireguardPeers() { return $this->hasMany(WireguardPeer::class); } }
